{
  "parameters": "z.object({ itemName: z.string().describe("The name of the armor item to equip, e.g., 'leather_chestplate'"), destination: z.enum(["head", "torso", "legs", "feet", "off-hand", "hand"]).describe("The equipment slot to use") })",
  "executionArgs": {
    "itemName": "leather_chestplate",
    "destination": "torso"
  },
  "code": "const normalize = function (val) {
  return val.toLowerCase().replace(/\s+/g, '_').replace(/^minecraft:/, '');
};
const requestedName = normalize(args.itemName);
const item = bot.inventory.items().find(function (i) {
  return normalize(i.name) === requestedName || (i.displayName && normalize(i.displayName) === requestedName);
});
if (!item) {
  return "<MISSING>: Could not find " + args.itemName + " in inventory.";
}
try {
  await bot.equip(item, args.destination);
  return "<EQUIPPED>: Put on " + (item.displayName || item.name) + " in " + args.destination + " slot.";
} catch (err) {
  return "<ERROR>: Failed to equip " + args.itemName + ": " + err.message;
}"
}
